const alert = $('Parse Alert').first().json;
let triage = {};
try {
  const raw = $input.first().json.message?.content ?? $input.first().json.text ?? $input.first().json.output ?? '';
  const m = String(raw).match(/\{[\s\S]*\}/);
  triage = m ? JSON.parse(m[0]) : { outcome: 'cannot_fix', summary_de: 'LLM-Antwort nicht parsebar', action_needed: true };
} catch (e) {
  triage = { outcome: 'cannot_fix', summary_de: 'LLM parse error: ' + e.message, action_needed: true, automatable: false };
}
const mayAutoFix = alert.allowAutoFix && triage.automatable === true && triage.outcome === 'auto_fix_candidate';
return [{ json: { ...alert, triage, mayAutoFix } }];

const a = $('Merge Triage').first().json;
const rem = $input.first().json;
const ok = rem.statusCode >= 200 && rem.statusCode < 300;
const text = ok
  ? `🔧 *Auto-Fix ausgeführt*

*${a.alertname}*
${a.triage.summary_de || ''}

Status: erledigt — bitte Alert/Metrik prüfen.`
  : `⚠️ *Auto-Fix fehlgeschlagen*

*${a.alertname}*
${a.triage.summary_de || ''}

HTTP ${rem.statusCode || '?'} — *Human-in-the-Loop*: Remediation-API prüfen oder manuell eingreifen.`;
return [{ json: { telegramText: text, parseMode: 'Markdown' } }];

const a = $input.first().json;
const t = a.triage || {};
const icon = { needs_human: '👤', cannot_fix: '🚫', no_action: 'ℹ️' }[t.outcome] || '🔔';
const hitl = t.outcome === 'needs_human' ? '

*Rückmeldung nötig* — antworte mit /ack oder Details.' : '';
const text = `${icon} *${a.status === 'resolved' ? 'OK' : 'FIRING'}: ${a.alertname}*

${t.telegram_message || t.summary_de || a.summary}

Severity: ${a.severity}
Namespace: ${a.namespace || '—'}
Outcome: ${t.outcome || 'unknown'}${hitl}
${a.runbookUrl ? '
' + a.runbookUrl : ''}`;
return [{ json: { telegramText: text, parseMode: 'Markdown' } }];
